INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4f4357a3-4447-4c5e-a99e-78f3aab7061b', $q$Free, unlimited-seat ATS$q$, $q$Post unlimited jobs and add unlimited team members without per-seat licensing fees.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4f4357a3-4447-4c5e-a99e-78f3aab7061b', $q$AI Applicant Scoring$q$, $q$Automatically ranks incoming resumes against a role's stated requirements to speed up first-pass screening.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4f4357a3-4447-4c5e-a99e-78f3aab7061b', $q$AI Note Taking$q$, $q$Summarizes recruiter and hiring-manager conversations with candidates so feedback stays consistent across a hiring loop.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4f4357a3-4447-4c5e-a99e-78f3aab7061b', $q$100+ job board syndication$q$, $q$Posts flow out automatically to more than 100 external job boards from a single listing.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4f4357a3-4447-4c5e-a99e-78f3aab7061b', $q$Gmail and Outlook integration$q$, $q$Recruiters can email and track candidate communication directly from their existing inbox.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4f4357a3-4447-4c5e-a99e-78f3aab7061b', $q$Unlimited free LinkedIn and X job posts$q$, $q$Premium subscribers get unlimited basic job listings on LinkedIn and X at no extra cost.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4f4357a3-4447-4c5e-a99e-78f3aab7061b', $q$Recruiting Partner Marketplace$q$, $q$Connects companies with vetted, fractional recruiters who set their own rates for project-based hiring support.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4f4357a3-4447-4c5e-a99e-78f3aab7061b', $q$Candidate pipeline tracking$q$, $q$Organizes applicants through customizable interview windows from application to offer.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4f4357a3-4447-4c5e-a99e-78f3aab7061b', $q$Free tier has no user or job caps, unusual among ATS products$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4f4357a3-4447-4c5e-a99e-78f3aab7061b', $q$Built-in AI resume scoring and note-taking reduce manual screening work$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4f4357a3-4447-4c5e-a99e-78f3aab7061b', $q$Access to a marketplace of fractional recruiters without a full-time hire$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4f4357a3-4447-4c5e-a99e-78f3aab7061b', $q$Strong job board reach with over 100 integrations from a single post$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4f4357a3-4447-4c5e-a99e-78f3aab7061b', $q$AI scoring and note-taking are gated behind the 199 dollars per month Premium plan$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4f4357a3-4447-4c5e-a99e-78f3aab7061b', $q$Smaller company than category leaders, so fewer deep integrations and enterprise controls$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4f4357a3-4447-4c5e-a99e-78f3aab7061b', $q$Recruiting Marketplace rates are set individually by recruiters, adding variable cost$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4f4357a3-4447-4c5e-a99e-78f3aab7061b', $q$Best suited to early-stage startups; less proven at large enterprise hiring scale$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4f4357a3-4447-4c5e-a99e-78f3aab7061b', $q$Is Dover free to use?$q$, $q$Yes. Dover's Free ATS plan has no cost and no limits on users or job postings; paid features are optional add-ons.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4f4357a3-4447-4c5e-a99e-78f3aab7061b', $q$How much does Dover's Premium ATS cost?$q$, $q$Premium ATS is 199 dollars per month and adds AI applicant scoring, AI note-taking, unlimited free LinkedIn and X job posts, and premium support.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4f4357a3-4447-4c5e-a99e-78f3aab7061b', $q$What is the Dover Recruiting Marketplace?$q$, $q$It is a network of independent, fractional recruiters that Dover customers can hire on a project basis; recruiters set their own rates.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4f4357a3-4447-4c5e-a99e-78f3aab7061b', $q$Who founded Dover and when?$q$, $q$Dover was founded in 2019 in San Francisco by George Carollo, Max Kolysh, and Anvisha Pai.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4f4357a3-4447-4c5e-a99e-78f3aab7061b', $q$Does Dover use artificial intelligence?$q$, $q$Yes, its Premium tier includes AI-based resume scoring against job requirements and AI-generated summaries of candidate conversations.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4f4357a3-4447-4c5e-a99e-78f3aab7061b', $q$Who are Dover's main competitors?$q$, $q$Dover competes with ATS platforms such as Greenhouse, Lever, Ashby, Workable, and Gem, most of which charge per-seat fees from the outset.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4f4357a3-4447-4c5e-a99e-78f3aab7061b', $q$First ATS for an early-stage startup$q$, $q$A founder or first recruiting hire replaces spreadsheets with a free, unlimited-seat system to track applicants across open roles.$q$, $q$Startup founders and early talent teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4f4357a3-4447-4c5e-a99e-78f3aab7061b', $q$AI-assisted resume screening$q$, $q$A growing company with high applicant volume upgrades to Premium to let AI scoring surface the strongest candidates first.$q$, $q$In-house recruiters and hiring managers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4f4357a3-4447-4c5e-a99e-78f3aab7061b', $q$On-demand recruiting support$q$, $q$A company facing a hiring surge engages a fractional recruiter through Dover's marketplace instead of hiring a full-time recruiter.$q$, $q$Operations leads and founders managing hiring spikes$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4f4357a3-4447-4c5e-a99e-78f3aab7061b', $q$Free ATS$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited users and jobs","100+ job board integrations","Gmail and Outlook integration","Candidate pipeline tracking","Help Center access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4f4357a3-4447-4c5e-a99e-78f3aab7061b', $q$Premium ATS$q$, $q$$199/month$q$, $q$Monthly$q$, NULL, $q$["Everything in Free ATS","Unlimited free basic LinkedIn job posts","Unlimited free X job posts","AI Applicant Scoring","AI Note Taking","Onboarding and premium support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4f4357a3-4447-4c5e-a99e-78f3aab7061b', $q$Recruiting Marketplace$q$, $q$Recruiters set their own rates$q$, $q$Project-based$q$, NULL, $q$["Access to vetted, fractional recruiters","Rates negotiated per engagement"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4f4357a3-4447-4c5e-a99e-78f3aab7061b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Dover is a San Francisco-based recruiting technology company offering a free applicant tracking system paired with AI-powered candidate scoring and an on-demand marketplace of fractional recruiters.$q$, $q$Founded in 2019 by George Carollo, Max Kolysh, and Anvisha Pai, and backed by a Y Combinator batch and a 2021 Series A led by Tiger Global, Dover positions itself as recruiting infrastructure for startups that cannot yet justify enterprise ATS pricing.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4f4357a3-4447-4c5e-a99e-78f3aab7061b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The Free ATS tier includes unlimited users and job listings, syndication to more than 100 job boards, Gmail and Outlook integration, and candidate pipeline tracking.$q$, $q$Premium ATS adds AI Applicant Scoring, which ranks incoming resumes against role requirements, and AI Note Taking, which summarizes interview and screening conversations automatically.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4f4357a3-4447-4c5e-a99e-78f3aab7061b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Dover's Free ATS plan costs nothing and has no seat or job limits, making it usable indefinitely by very small teams.$q$, $q$The Premium ATS plan is 199 dollars per month and unlocks unlimited free job posts on LinkedIn and X plus AI scoring, AI note-taking, and premium support. The Recruiting Marketplace operates separately, with independent fractional recruiters setting their own rates.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4f4357a3-4447-4c5e-a99e-78f3aab7061b', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4f4357a3-4447-4c5e-a99e-78f3aab7061b', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4f4357a3-4447-4c5e-a99e-78f3aab7061b', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4f4357a3-4447-4c5e-a99e-78f3aab7061b', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Automated ingestion channels$q$, $q$Pull interviews, calls, and support tickets in automatically from tools like Zoom, Gong, Intercom, and Zendesk.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$AI summaries and transcription$q$, $q$Automatically transcribes recordings and generates concise summaries of long-form qualitative data.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$AI chat across research data$q$, $q$Ask natural-language questions about your entire research corpus and get synthesized, cited answers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Tagging and highlight reels$q$, $q$Manually tag and clip key moments from interviews to build reusable evidence for findings.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Docs and shareable insights$q$, $q$Combine findings, quotes, and clips into shareable documents for stakeholders outside the research team.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Personas and journey maps$q$, $q$Turn raw research into structured artifacts the whole product organization can reference.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Enterprise security controls$q$, $q$Single sign-on, audit logs, custom data retention, and a HIPAA add-on for regulated industries.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Integrations and templates$q$, $q$Calendar sync, search integrations, and pre-built templates to speed up research operations.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Strong AI-assisted synthesis reduces manual coding of qualitative data$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Automated channels keep the repository updated without manual uploads$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Free plan lets small teams or individuals try the product with no card required$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Enterprise-grade security options support regulated industries like healthcare$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Per-seat pricing can get expensive as more stakeholders need access$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Free plan is limited to a single project and a single ingestion channel$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Enterprise pricing is custom and not published, requiring a sales conversation$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Usage-based add-ons like extra Channels add further cost on top of seat fees$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Is Dovetail free to use?$q$, $q$Dovetail offers a Free plan with one project, one data channel, basic AI summaries, and no credit card required; deeper functionality requires a paid plan.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$How much does Dovetail cost per user?$q$, $q$Third-party pricing trackers report a mid-tier plan around 29 to 39 dollars per user per month when billed annually; Enterprise pricing is custom-quoted.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Who founded Dovetail?$q$, $q$Dovetail was founded in 2017 in Sydney, Australia by Benjamin Humphrey and Bradley Ayers, both former Atlassian employees.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$What does Dovetail do with AI?$q$, $q$It transcribes recordings, generates summaries, tags recurring themes, and powers an AI chat interface that answers questions across a team's full research repository.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Is Dovetail HIPAA compliant?$q$, $q$Dovetail offers a HIPAA add-on as part of its Enterprise plan for organizations handling regulated health data.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$What are Dovetail's main competitors?$q$, $q$Dovetail competes with research repository and insights tools such as Condens, EnjoyHQ, Marvin, and UserTesting.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Centralizing scattered user research$q$, $q$A product team consolidates interviews, surveys, and call recordings from multiple tools into one searchable repository.$q$, $q$User researchers and design teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Synthesizing customer feedback at scale$q$, $q$A product manager uses AI chat to quickly answer questions like what enterprise customers say about a specific feature across hundreds of source clips.$q$, $q$Product managers and product marketers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Sharing findings across the organization$q$, $q$A research team builds shareable Docs with quotes and clips so sales and leadership can see evidence behind product decisions.$q$, $q$Cross-functional stakeholders and leadership$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Free$q$, $q$$0/month$q$, $q$N/A$q$, NULL, $q$["1 channel for feedback tracking","1 project","AI chat for instant answers","Basic AI summaries","Calendar, search, and contact integrations","Templates and global tags"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Professional$q$, $q$~$29-$39/user/month (billed annually, per third-party trackers)$q$, $q$Annual$q$, NULL, $q$["Unlimited projects","Advanced analysis tools","More integrations","Higher transcription and storage limits"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Enterprise$q$, $q$Custom (invoiced)$q$, $q$Custom$q$, NULL, $q$["Unlimited AI agents and channels","AI dashboards","Unlimited Docs and projects","Single sign-on and audit logs","HIPAA add-on available","Dedicated customer success manager"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Dovetail is a research and customer insights repository founded in Sydney, Australia in 2017 by former Atlassian colleagues Benjamin Humphrey and Bradley Ayers.$q$, $q$The platform ingests interviews, transcripts, surveys, and support tickets, then uses AI to summarize and surface themes across an organization's qualitative customer data.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Automated data ingestion channels pull recordings and tickets in from tools like Zoom, Gong, Intercom, and Zendesk, while AI transcribes and tags the content.$q$, $q$An AI chat interface lets teams ask natural-language questions across their entire research corpus and get synthesized, source-linked answers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Dovetail's Free plan supports one project and one channel with basic AI summaries and no credit card required.$q$, $q$Paid per-seat tiers (reported around 29 to 39 dollars per user per month annually) unlock unlimited projects and deeper AI features, while Enterprise is custom-quoted and adds SSO, audit logs, and a HIPAA add-on.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0608cdcb-8ede-4cee-a620-9cc6d15af341', $q$Playlist, album, and track downloads$q$, $q$Paste a Spotify link and download the corresponding tracks, album, or full playlist.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0608cdcb-8ede-4cee-a620-9cc6d15af341', $q$Playlist Monitor$q$, $q$Automatically watches a saved playlist and downloads new tracks as they are added, without manual re-triggering.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0608cdcb-8ede-4cee-a620-9cc6d15af341', $q$Multiple audio formats$q$, $q$Export to MP3, FLAC, M4A, OGG, or OPUS at a user-selected bitrate.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0608cdcb-8ede-4cee-a620-9cc6d15af341', $q$Embedded synced lyrics$q$, $q$Fetches plain and time-synced lyrics from lrclib and embeds them directly into downloaded files.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0608cdcb-8ede-4cee-a620-9cc6d15af341', $q$Built-in web music player$q$, $q$Play downloaded tracks directly in the browser with shuffle, repeat, and volume controls.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0608cdcb-8ede-4cee-a620-9cc6d15af341', $q$Media-server-ready playlist export$q$, $q$Generates standard EXTM3U files compatible with Jellyfin, Navidrome, and Plex.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0608cdcb-8ede-4cee-a620-9cc6d15af341', $q$No API keys or Premium account required$q$, $q$Works entirely from Spotify's public embed metadata combined with YouTube Music matching.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0608cdcb-8ede-4cee-a620-9cc6d15af341', $q$Single-container Docker deployment$q$, $q$Runs as one Docker image with persistent volumes for downloads and app data, plus home-server app store packages.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0608cdcb-8ede-4cee-a620-9cc6d15af341', $q$Completely free, open-source, and self-hosted with no subscription$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0608cdcb-8ede-4cee-a620-9cc6d15af341', $q$No Spotify API credentials or Premium account needed to use it$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0608cdcb-8ede-4cee-a620-9cc6d15af341', $q$Playlist Monitor keeps a local library automatically in sync with a Spotify playlist$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0608cdcb-8ede-4cee-a620-9cc6d15af341', $q$Simple one-command Docker deployment plus home-server app store packages$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0608cdcb-8ede-4cee-a620-9cc6d15af341', $q$Audio comes from YouTube Music matches rather than Spotify's actual audio streams, so match quality can vary$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0608cdcb-8ede-4cee-a620-9cc6d15af341', $q$Requires self-hosting knowledge and your own server or home-lab infrastructure$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0608cdcb-8ede-4cee-a620-9cc6d15af341', $q$Maintained by a single independent developer rather than a company, with no formal support guarantees$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0608cdcb-8ede-4cee-a620-9cc6d15af341', $q$Downloading copyrighted content may conflict with Spotify's terms of service depending on jurisdiction and use$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0608cdcb-8ede-4cee-a620-9cc6d15af341', $q$Is Downtify free?$q$, $q$Yes. Downtify is fully free and open source under the GPL-3.0 license, with no subscription or paid tier.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0608cdcb-8ede-4cee-a620-9cc6d15af341', $q$Do I need a Spotify Premium account to use Downtify?$q$, $q$No. Downtify reads Spotify's public embed metadata and does not require a Premium account or API credentials.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0608cdcb-8ede-4cee-a620-9cc6d15af341', $q$What audio formats does Downtify support?$q$, $q$MP3, FLAC, M4A, OGG, and OPUS, each at a bitrate you choose.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0608cdcb-8ede-4cee-a620-9cc6d15af341', $q$How do I install Downtify?$q$, $q$Run its official Docker image with a single command, use Docker Compose, or install it via community packages for Umbrel, CasaOS, or HomeDock.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0608cdcb-8ede-4cee-a620-9cc6d15af341', $q$What is Downtify's Playlist Monitor?$q$, $q$A feature that periodically checks a saved playlist and automatically downloads any newly added tracks.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0608cdcb-8ede-4cee-a620-9cc6d15af341', $q$Who maintains Downtify?$q$, $q$It is built and maintained by an independent developer, henriquesebastiao, with the source code publicly hosted on GitHub.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0608cdcb-8ede-4cee-a620-9cc6d15af341', $q$Building an offline personal music library$q$, $q$A self-hoster downloads favorite Spotify playlists to keep a permanent, offline, properly tagged local copy.$q$, $q$Self-hosting and home-lab enthusiasts$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0608cdcb-8ede-4cee-a620-9cc6d15af341', $q$Feeding a home media server$q$, $q$A user exports EXTM3U playlists compatible with Jellyfin, Navidrome, or Plex to integrate downloaded music into an existing media setup.$q$, $q$Home media server operators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0608cdcb-8ede-4cee-a620-9cc6d15af341', $q$Auto-archiving a growing playlist$q$, $q$A user sets up Playlist Monitor on a collaborative playlist so every newly added track is automatically downloaded and tagged.$q$, $q$Music collectors and playlist curators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0608cdcb-8ede-4cee-a620-9cc6d15af341', $q$Self-hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited downloads on your own infrastructure","All audio formats and features included","No account or subscription required","Community support via GitHub"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0608cdcb-8ede-4cee-a620-9cc6d15af341', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Downtify is an open-source, self-hosted tool that converts Spotify playlists, albums, and tracks into locally stored, properly tagged audio files.$q$, $q$Created by developer henriquesebastiao and released under the GPL-3.0 license, it runs entirely inside a single Docker container with no Spotify API keys or Premium subscription required.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0608cdcb-8ede-4cee-a620-9cc6d15af341', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$It reads public Spotify metadata, finds a matching track on YouTube Music, and processes audio through yt-dlp and ffmpeg before tagging files with mutagen.$q$, $q$Notable features include a Playlist Monitor for auto-downloading new tracks, five supported audio formats, embedded synced lyrics, and a built-in web music player.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0608cdcb-8ede-4cee-a620-9cc6d15af341', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Downtify is completely free and open source; there are no paid tiers, subscriptions, or licensing fees.$q$, $q$Users deploy their own instance via Docker or Docker Compose, or through community packages for home-server platforms like Umbrel, CasaOS, and HomeDock.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0608cdcb-8ede-4cee-a620-9cc6d15af341', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0608cdcb-8ede-4cee-a620-9cc6d15af341', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0608cdcb-8ede-4cee-a620-9cc6d15af341', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0608cdcb-8ede-4cee-a620-9cc6d15af341', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe1e4171-5d16-4d7e-a68f-6c8c85d5aa76', $q$Ambient Agent (AI tracking)$q$, $q$Automatically tracks and reports on product development progress across connected tools like Jira, Azure DevOps, Asana, and Slack.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe1e4171-5d16-4d7e-a68f-6c8c85d5aa76', $q$Portfolio-wide roadmapping$q$, $q$Visualizes multiple teams' roadmaps on a single timeline to support cross-portfolio prioritization.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe1e4171-5d16-4d7e-a68f-6c8c85d5aa76', $q$Strategy-to-outcome connections$q$, $q$Links company objectives down through initiatives and features so leadership can see strategic alignment.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe1e4171-5d16-4d7e-a68f-6c8c85d5aa76', $q$Customer insight aggregation$q$, $q$Collects and organizes customer feedback to inform prioritization decisions.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe1e4171-5d16-4d7e-a68f-6c8c85d5aa76', $q$Portfolio trend and risk analysis$q$, $q$Flags dependencies and predicts portfolio risks before they cause delivery delays (Enterprise tier).$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe1e4171-5d16-4d7e-a68f-6c8c85d5aa76', $q$Free read-only and requestor access$q$, $q$Starter plan includes access for up to 100 additional stakeholders without full paid seats.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe1e4171-5d16-4d7e-a68f-6c8c85d5aa76', $q$Enterprise security controls$q$, $q$Two-factor authentication and single sign-on via Microsoft Entra ID or Okta.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe1e4171-5d16-4d7e-a68f-6c8c85d5aa76', $q$Optional Advanced Apps$q$, $q$Add-on modules for advanced strategy, idea management, resource planning, and product development lifecycle tracking.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fe1e4171-5d16-4d7e-a68f-6c8c85d5aa76', $q$Purpose-built for portfolio-level strategy, not just single-team roadmaps$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fe1e4171-5d16-4d7e-a68f-6c8c85d5aa76', $q$AI Ambient Agent reduces manual status-update work by pulling data from delivery tools$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fe1e4171-5d16-4d7e-a68f-6c8c85d5aa76', $q$Free read-only or requestor access for up to 100 users lowers the cost of broad stakeholder visibility$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fe1e4171-5d16-4d7e-a68f-6c8c85d5aa76', $q$Strong support for complex, multi-level organizational hierarchies at the Enterprise tier$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fe1e4171-5d16-4d7e-a68f-6c8c85d5aa76', $q$Pricing is not published and requires a sales conversation for both tiers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fe1e4171-5d16-4d7e-a68f-6c8c85d5aa76', $q$Advanced capabilities like predictive risk analysis are reserved for the Enterprise plan$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fe1e4171-5d16-4d7e-a68f-6c8c85d5aa76', $q$Some deeper functionality is sold as separate paid Advanced Apps rather than included$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fe1e4171-5d16-4d7e-a68f-6c8c85d5aa76', $q$Best suited to multi-team or multi-product organizations; may be more than a single small product team needs$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fe1e4171-5d16-4d7e-a68f-6c8c85d5aa76', $q$How much does Dragonboat cost?$q$, $q$Dragonboat does not publish fixed pricing; both its Starter and Enterprise plans require contacting sales for a custom quote.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fe1e4171-5d16-4d7e-a68f-6c8c85d5aa76', $q$Who founded Dragonboat?$q$, $q$Dragonboat was founded in 2018 in Santa Clara, California, by CEO Becky Flint and co-founder Lee Bailey.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fe1e4171-5d16-4d7e-a68f-6c8c85d5aa76', $q$What is Dragonboat's Ambient Agent?$q$, $q$It is an AI feature that automatically tracks and reports on product development progress by pulling status data from tools like Jira, Azure DevOps, Asana, and Slack.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fe1e4171-5d16-4d7e-a68f-6c8c85d5aa76', $q$How much funding has Dragonboat raised?$q$, $q$Dragonboat has raised approximately 15 million dollars, including a 3 million dollar seed round and a 12 million dollar Series A led by Insight Partners.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fe1e4171-5d16-4d7e-a68f-6c8c85d5aa76', $q$Who is Dragonboat designed for?$q$, $q$It is designed for VPs of product, Chief Product Officers, and product operations teams managing multiple product lines or business units.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fe1e4171-5d16-4d7e-a68f-6c8c85d5aa76', $q$What are Dragonboat's main competitors?$q$, $q$Dragonboat competes with Productboard, Aha!, Jira Product Discovery, and other roadmapping and product portfolio tools.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fe1e4171-5d16-4d7e-a68f-6c8c85d5aa76', $q$Aligning multi-team roadmaps with strategy$q$, $q$A Chief Product Officer connects company-level objectives to every product team's roadmap in one shared view.$q$, $q$CPOs and VPs of Product$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fe1e4171-5d16-4d7e-a68f-6c8c85d5aa76', $q$Automating portfolio status reporting$q$, $q$A product operations team uses the Ambient Agent to pull live status from Jira and Slack instead of manually compiling reports.$q$, $q$Product operations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fe1e4171-5d16-4d7e-a68f-6c8c85d5aa76', $q$Prioritizing across business units$q$, $q$A large enterprise with several product lines uses portfolio trend analysis to spot dependencies and risks before they delay delivery.$q$, $q$Enterprise product portfolio managers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fe1e4171-5d16-4d7e-a68f-6c8c85d5aa76', $q$Starter$q$, $q$Custom (contact sales)$q$, $q$Custom$q$, NULL, $q$["Ambient Agent integrations with Jira, ADO, Asana, Slack","Strategy and outcomes connected to roadmaps","Customer insight and prioritization tools","Portfolio-wide roadmap building","Free read-only and requestor access for up to 100 users"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fe1e4171-5d16-4d7e-a68f-6c8c85d5aa76', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$Custom$q$, NULL, $q$["Everything in Starter","Support for complex, multi-level organizational hierarchies","Custom enterprise system configurations","Portfolio trend and risk analysis","Advanced integrations and data transformation","Two-factor authentication and SSO (Microsoft Entra ID / Okta)","Dedicated Customer Success Manager"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fe1e4171-5d16-4d7e-a68f-6c8c85d5aa76', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Dragonboat is a Santa Clara, California-based strategic product portfolio management platform founded in 2018 by Becky Flint and Lee Bailey.$q$, $q$It connects company strategy and objectives to multi-team roadmaps and execution data, targeting product leaders who manage several product lines or business units at once.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fe1e4171-5d16-4d7e-a68f-6c8c85d5aa76', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Its Ambient Agent uses AI to automatically track and report on product development progress by pulling data from Jira, Azure DevOps, Asana, and Slack.$q$, $q$The platform supports portfolio-wide roadmapping, customer insight aggregation, configurable prioritization frameworks, and predictive risk and dependency analysis for enterprise customers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fe1e4171-5d16-4d7e-a68f-6c8c85d5aa76', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Dragonboat does not publish fixed prices; both its Starter and Enterprise plans are quoted after contacting sales.$q$, $q$Starter includes free read-only or requestor access for up to 100 additional users, while Enterprise adds complex hierarchy support, advanced security, and a dedicated customer success manager. Optional Advanced Apps are sold separately.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fe1e4171-5d16-4d7e-a68f-6c8c85d5aa76', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fe1e4171-5d16-4d7e-a68f-6c8c85d5aa76', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fe1e4171-5d16-4d7e-a68f-6c8c85d5aa76', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9a28f7a9-0896-4972-aa26-4337e26797f9', $q$Redis-protocol compatibility$q$, $q$Supports RESP2 and RESP3 and over 240 Redis commands, so existing Redis clients and tools work without code changes.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9a28f7a9-0896-4972-aa26-4337e26797f9', $q$Multi-threaded, shared-nothing architecture$q$, $q$Written in C++ to scale across all available CPU cores, unlike Redis's traditionally single-threaded core.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9a28f7a9-0896-4972-aa26-4337e26797f9', $q$Memcached compatibility$q$, $q$Can also serve as a drop-in replacement for Memcached-based caching layers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9a28f7a9-0896-4972-aa26-4337e26797f9', $q$Source-available under BSL 1.1$q$, $q$Code is free to self-host and modify, with a restriction against offering it as a competing hosted database service.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9a28f7a9-0896-4972-aa26-4337e26797f9', $q$Fully managed Dragonfly Cloud$q$, $q$One-click provisioning on AWS, GCP, or Azure with horizontal and vertical scaling and a monitoring dashboard.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9a28f7a9-0896-4972-aa26-4337e26797f9', $q$Bring-your-own-cloud deployment$q$, $q$Business and Enterprise tiers let customers run Dragonfly Cloud inside their own cloud account.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9a28f7a9-0896-4972-aa26-4337e26797f9', $q$Enterprise security controls$q$, $q$SSO, multi-factor authentication, custom SLAs, and air-gapped infrastructure support at higher tiers.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9a28f7a9-0896-4972-aa26-4337e26797f9', $q$Improved memory efficiency$q$, $q$Marketed memory efficiency gains of around 20 percent compared with equivalent Redis deployments.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9a28f7a9-0896-4972-aa26-4337e26797f9', $q$Free to self-host with source code publicly available on GitHub$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9a28f7a9-0896-4972-aa26-4337e26797f9', $q$Drop-in compatibility with existing Redis clients and tooling minimizes migration work$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9a28f7a9-0896-4972-aa26-4337e26797f9', $q$Multi-threaded architecture delivers higher throughput per server than single-threaded Redis in many workloads$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9a28f7a9-0896-4972-aa26-4337e26797f9', $q$Offers both a self-hosted path and a fully managed cloud option for teams that want either$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9a28f7a9-0896-4972-aa26-4337e26797f9', $q$Business Source License 1.1 is not an OSI-approved open-source license and restricts competing hosted offerings$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9a28f7a9-0896-4972-aa26-4337e26797f9', $q$Managed Business tier starts around 2,000 dollars per month, a steep jump from the self-serve Flex tier$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9a28f7a9-0896-4972-aa26-4337e26797f9', $q$Younger company (founded 2022) with a smaller ecosystem and community than long-established Redis$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9a28f7a9-0896-4972-aa26-4337e26797f9', $q$Enterprise pricing is not published and requires a direct sales conversation$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9a28f7a9-0896-4972-aa26-4337e26797f9', $q$Is Dragonfly open source?$q$, $q$Dragonfly's source code is publicly available on GitHub under the Business Source License 1.1, which allows free self-hosting and modification but is not an OSI-approved open-source license; it converts to Apache 2.0 after a set number of years.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9a28f7a9-0896-4972-aa26-4337e26797f9', $q$Is Dragonfly compatible with Redis?$q$, $q$Yes. Dragonfly implements the RESP2 and RESP3 protocols and over 240 Redis commands, so most existing Redis clients and tools work without modification.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9a28f7a9-0896-4972-aa26-4337e26797f9', $q$How much does Dragonfly Cloud cost?$q$, $q$Dragonfly Cloud starts with a Flex plan around 36 dollars per month, a Business plan around 2,000 dollars per month, and custom Enterprise pricing for large organizations.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9a28f7a9-0896-4972-aa26-4337e26797f9', $q$Who founded Dragonfly?$q$, $q$Dragonfly was founded in March 2022 by former Google engineers Roman Gershman and Oded Poncz.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9a28f7a9-0896-4972-aa26-4337e26797f9', $q$Can I self-host Dragonfly for free?$q$, $q$Yes. Dragonfly can be self-hosted at no cost under its source-available license; Dragonfly Cloud is the paid, fully managed alternative.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9a28f7a9-0896-4972-aa26-4337e26797f9', $q$What are Dragonfly's main competitors?$q$, $q$Dragonfly competes with Redis, Redis's own managed cloud, KeyDB, Valkey, and Memcached.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9a28f7a9-0896-4972-aa26-4337e26797f9', $q$Replacing Redis for higher throughput$q$, $q$A backend team migrates an existing Redis caching layer to Dragonfly to get higher throughput per server without changing client code.$q$, $q$Backend and infrastructure engineers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9a28f7a9-0896-4972-aa26-4337e26797f9', $q$Managed in-memory data store for production apps$q$, $q$A startup uses Dragonfly Cloud's Flex plan to get a fully managed, auto-scaling cache without operating infrastructure themselves.$q$, $q$Startups and small engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9a28f7a9-0896-4972-aa26-4337e26797f9', $q$Regulated, bring-your-own-cloud deployments$q$, $q$An enterprise with compliance requirements runs Dragonfly Cloud's Business tier inside its own cloud account with SSO and custom SLAs.$q$, $q$Enterprise platform and security teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9a28f7a9-0896-4972-aa26-4337e26797f9', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full Redis and Memcached protocol compatibility","Run on your own infrastructure","Source-available under BSL 1.1"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9a28f7a9-0896-4972-aa26-4337e26797f9', $q$Flex (Dragonfly Cloud)$q$, $q$From $36/month$q$, $q$Monthly$q$, NULL, $q$["Fully-managed on AWS, GCP, or Azure","One-click provisioning","Horizontal and vertical scaling","Monitoring dashboard"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9a28f7a9-0896-4972-aa26-4337e26797f9', $q$Business (Dragonfly Cloud)$q$, $q$From $2,000/month$q$, $q$Monthly$q$, NULL, $q$["Bring your own cloud","Auto-scaling","SSO and MFA","Custom SLA","Dedicated support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9a28f7a9-0896-4972-aa26-4337e26797f9', $q$Enterprise (Dragonfly Cloud)$q$, $q$Custom (contact sales)$q$, $q$Custom$q$, NULL, $q$["Air-gapped infrastructure support","Custom instance types","White-glove migrations","Advanced security and compliance","Enterprise SLA"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9a28f7a9-0896-4972-aa26-4337e26797f9', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Dragonfly (DragonflyDB) is an in-memory data store built as a high-performance, drop-in replacement for Redis and Memcached, founded in 2022 by former Google engineers Roman Gershman and Oded Poncz.$q$, $q$The company is dual-headquartered in Tel Aviv and San Francisco and raised 21 million dollars in combined seed and Series A funding led by Redpoint Ventures and Quiet Capital.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9a28f7a9-0896-4972-aa26-4337e26797f9', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Written from scratch in C++ with a shared-nothing, multi-threaded architecture, Dragonfly scales across all CPU cores while remaining wire-compatible with Redis's RESP2 and RESP3 protocols and over 240 Redis commands.$q$, $q$The source code is publicly available under the Business Source License 1.1, which permits free self-hosting and modification but restricts offering Dragonfly itself as a competing hosted database service; the license converts to Apache 2.0 after a set number of years.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9a28f7a9-0896-4972-aa26-4337e26797f9', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Self-hosting Dragonfly is free under its source-available license.$q$, $q$Dragonfly Cloud, the managed service, starts with a self-serve Flex plan around 36 dollars per month, a Business plan around 2,000 dollars per month for advanced security and support, and custom Enterprise pricing for air-gapped deployments, with on-demand usage priced around 8 dollars per gigabyte of memory per month.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9a28f7a9-0896-4972-aa26-4337e26797f9', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9a28f7a9-0896-4972-aa26-4337e26797f9', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9a28f7a9-0896-4972-aa26-4337e26797f9', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9a28f7a9-0896-4972-aa26-4337e26797f9', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b0661eaf-0146-4993-862a-300b62279f7d', $q$Continuous control monitoring$q$, $q$Automatically flags control drift, such as unrevoked access after an employee offboarding, as it happens rather than at audit time.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b0661eaf-0146-4993-862a-300b62279f7d', $q$Automated evidence collection$q$, $q$Pulls evidence directly from connected cloud, identity, HR, and engineering tools instead of manual screenshots and spreadsheets.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b0661eaf-0146-4993-862a-300b62279f7d', $q$Multi-framework support$q$, $q$Maps a single set of evidence to multiple frameworks including SOC 2, ISO 27001, HIPAA, PCI DSS, and GDPR.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b0661eaf-0146-4993-862a-300b62279f7d', $q$Vetted auditor network$q$, $q$Connects customers to more than 2,500 independent auditors who can review evidence directly inside the platform.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b0661eaf-0146-4993-862a-300b62279f7d', $q$Public trust pages$q$, $q$Lets companies show customers and prospects a real-time view of their security and compliance posture.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b0661eaf-0146-4993-862a-300b62279f7d', $q$Policy and risk management$q$, $q$Centralizes security policies, risk assessments, and employee acknowledgments in one system of record.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b0661eaf-0146-4993-862a-300b62279f7d', $q$Vendor risk management$q$, $q$Helps security teams assess and monitor the compliance posture of their own third-party vendors.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b0661eaf-0146-4993-862a-300b62279f7d', $q$Broad integration ecosystem$q$, $q$Connects to AWS, Azure, Google Cloud, identity providers, ticketing tools, and version control systems.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b0661eaf-0146-4993-862a-300b62279f7d', $q$Continuous, automated monitoring reduces manual audit-prep work throughout the year$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b0661eaf-0146-4993-862a-300b62279f7d', $q$Broad framework coverage lets one evidence base support multiple certifications$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b0661eaf-0146-4993-862a-300b62279f7d', $q$Large, vetted auditor network streamlines running the actual audit$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b0661eaf-0146-4993-862a-300b62279f7d', $q$Trusted by well-known technology companies, reflecting strong enterprise credibility$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b0661eaf-0146-4993-862a-300b62279f7d', $q$Pricing is not published and requires a sales conversation, making budgeting harder upfront$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b0661eaf-0146-4993-862a-300b62279f7d', $q$Third-party estimates put annual costs from roughly 7,500 up to 100,000 dollars depending on scope, a wide range$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b0661eaf-0146-4993-862a-300b62279f7d', $q$Primarily suited to companies with a modern cloud stack; less turnkey for legacy on-premise environments$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b0661eaf-0146-4993-862a-300b62279f7d', $q$Multi-framework, multi-integration setups can require significant initial configuration effort$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b0661eaf-0146-4993-862a-300b62279f7d', $q$How much does Drata cost?$q$, $q$Drata does not publish pricing publicly. Third-party estimates report tiers roughly from 7,500 dollars per year at the entry level to 15,000 dollars per year for a mid-tier plan, with custom pricing for larger, multi-framework customers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b0661eaf-0146-4993-862a-300b62279f7d', $q$Who founded Drata?$q$, $q$Drata was founded in 2020 in San Diego, California, by Adam Markowitz, Daniel Marashlian, and Troy Markowitz.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b0661eaf-0146-4993-862a-300b62279f7d', $q$What compliance frameworks does Drata support?$q$, $q$Drata supports SOC 2, ISO 27001, HIPAA, PCI DSS, GDPR, and other common security and privacy frameworks.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b0661eaf-0146-4993-862a-300b62279f7d', $q$How much funding has Drata raised?$q$, $q$Drata has raised 328 million dollars across four rounds, including a 200 million dollar Series C in December 2022 at a 2 billion dollar valuation.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b0661eaf-0146-4993-862a-300b62279f7d', $q$Does Drata help with the actual audit, not just evidence collection?$q$, $q$Yes. Drata connects customers to a network of more than 2,500 vetted independent auditors who can review evidence directly within the platform.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b0661eaf-0146-4993-862a-300b62279f7d', $q$What are Drata's main competitors?$q$, $q$Drata's closest competitor is Vanta, with Secureframe, Sprinto, and Thoropass also competing in the compliance automation space.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b0661eaf-0146-4993-862a-300b62279f7d', $q$Achieving SOC 2 for the first time$q$, $q$An early-stage SaaS startup uses Drata to collect evidence and pass its first SOC 2 Type II audit in order to close enterprise deals.$q$, $q$Startup security and engineering leaders$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b0661eaf-0146-4993-862a-300b62279f7d', $q$Maintaining continuous compliance year-round$q$, $q$A scale-up with existing certifications uses continuous monitoring to catch control drift immediately instead of scrambling before each audit renewal.$q$, $q$Compliance and IT teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b0661eaf-0146-4993-862a-300b62279f7d', $q$Supporting multi-framework enterprise sales$q$, $q$A growing company pursuing ISO 27001 and HIPAA alongside SOC 2 reuses a shared evidence base across all three frameworks to unblock enterprise contracts.$q$, $q$Enterprise sales and security leadership$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b0661eaf-0146-4993-862a-300b62279f7d', $q$Essential$q$, $q$~$7,500/year (third-party estimate)$q$, $q$Annual$q$, NULL, $q$["Single framework coverage","Automated evidence collection","Continuous control monitoring","Core policy templates"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b0661eaf-0146-4993-862a-300b62279f7d', $q$Foundation$q$, $q$~$15,000/year (third-party estimate)$q$, $q$Annual$q$, NULL, $q$["Everything in Essential","Additional framework coverage","Expanded integrations","Vendor risk management"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b0661eaf-0146-4993-862a-300b62279f7d', $q$Advanced$q$, $q$Custom (contact sales)$q$, $q$Annual$q$, NULL, $q$["Multi-framework, multi-entity support","Advanced integrations and automation","Dedicated support","Custom contract terms"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b0661eaf-0146-4993-862a-300b62279f7d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Drata is a San Diego-based compliance automation platform founded in 2020 by Adam Markowitz, Daniel Marashlian, and Troy Markowitz.$q$, $q$It has raised 328 million dollars in total funding, including a 200 million dollar Series C in December 2022 at a 2 billion dollar valuation, and reports over 100 million dollars in annual recurring revenue serving more than 7,000 customers.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b0661eaf-0146-4993-862a-300b62279f7d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Drata connects to a company's cloud infrastructure, identity, HR, and engineering tools to continuously collect evidence and monitor security controls in near real time.$q$, $q$It maps continuous evidence to frameworks including SOC 2, ISO 27001, HIPAA, PCI DSS, and GDPR, and connects customers to a network of more than 2,500 vetted independent auditors.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b0661eaf-0146-4993-862a-300b62279f7d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Drata does not publish pricing; it sells custom annual contracts sized to a company's frameworks, integrations, and headcount.$q$, $q$Third-party benchmarks report roughly three tiers, from an entry Essential tier around 7,500 dollars per year to a Foundation tier around 15,000 dollars per year, up to a custom-priced Advanced tier for large, multi-framework customers.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b0661eaf-0146-4993-862a-300b62279f7d', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b0661eaf-0146-4993-862a-300b62279f7d', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b0661eaf-0146-4993-862a-300b62279f7d', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('24cc901e-5be4-49f1-a1da-9b6b8e0ccdd4', $q$Real-time collaborative canvas$q$, $q$Multiple users see each other's cursors and brushstrokes live as they draw on the same canvas.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('24cc901e-5be4-49f1-a1da-9b6b8e0ccdd4', $q$200+ built-in brushes and a brush editor$q$, $q$Comes with a large brush library across multiple brush engines, plus tools to build fully custom brushes.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('24cc901e-5be4-49f1-a1da-9b6b8e0ccdd4', $q$Layers, blend modes, and selections$q$, $q$Supports layers, layer groups, blending modes, shape tools, transforms, and flood fill for standard painting workflows.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('24cc901e-5be4-49f1-a1da-9b6b8e0ccdd4', $q$Animation with onion skinning$q$, $q$A timeline and onion-skin feature enable rudimentary frame-by-frame animation.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('24cc901e-5be4-49f1-a1da-9b6b8e0ccdd4', $q$Crash and session recovery$q$, $q$Recovers an interrupted drawing session almost exactly where it left off after a crash, forced reboot, or app termination.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('24cc901e-5be4-49f1-a1da-9b6b8e0ccdd4', $q$Built-in timelapse recorder$q$, $q$Generates a video of the entire drawing or animation process, optionally cropped to a chosen canvas area.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('24cc901e-5be4-49f1-a1da-9b6b8e0ccdd4', $q$OpenRaster and PSD support$q$, $q$Imports and exports files in the OpenRaster (ORA) format and Photoshop's PSD format for interoperability.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('24cc901e-5be4-49f1-a1da-9b6b8e0ccdd4', $q$Password-protected private sessions$q$, $q$Sessions can be made public or locked with a password so only invited collaborators can join.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('24cc901e-5be4-49f1-a1da-9b6b8e0ccdd4', $q$Completely free and open source under the GPLv3 license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('24cc901e-5be4-49f1-a1da-9b6b8e0ccdd4', $q$Genuine real-time multi-user drawing with no per-seat cost or account requirement$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('24cc901e-5be4-49f1-a1da-9b6b8e0ccdd4', $q$Available on Windows, macOS, Linux, Android, and via a browser-based version$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('24cc901e-5be4-49f1-a1da-9b6b8e0ccdd4', $q$Governed by a non-profit structure explicitly designed to keep the software public and free permanently$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('24cc901e-5be4-49f1-a1da-9b6b8e0ccdd4', $q$Development is driven by a small team, so feature velocity can be slower than well-funded commercial tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('24cc901e-5be4-49f1-a1da-9b6b8e0ccdd4', $q$Lacks some advanced digital-painting features found in dedicated commercial apps like Photoshop or Clip Studio Paint$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('24cc901e-5be4-49f1-a1da-9b6b8e0ccdd4', $q$Real-time collaboration performance depends on the server used, whether self-hosted or a community server$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('24cc901e-5be4-49f1-a1da-9b6b8e0ccdd4', $q$Animation tools are described as rudimentary rather than a full animation production suite$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('24cc901e-5be4-49f1-a1da-9b6b8e0ccdd4', $q$Is Drawpile free?$q$, $q$Yes. Drawpile is completely free, open-source software licensed under the GPLv3, with no subscription or paid tier.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('24cc901e-5be4-49f1-a1da-9b6b8e0ccdd4', $q$What platforms does Drawpile support?$q$, $q$Drawpile runs natively on Windows, macOS, Linux, and Android, and has a browser-based version usable on devices like iPad and iPhone.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('24cc901e-5be4-49f1-a1da-9b6b8e0ccdd4', $q$Who maintains Drawpile?$q$, $q$Drawpile is maintained by a small core team under Drawpile gemeinnützige UG, a German non-profit organization, with contributions from a wider community.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('24cc901e-5be4-49f1-a1da-9b6b8e0ccdd4', $q$Can I host my own Drawpile server?$q$, $q$Yes. Users can self-host a session server or connect to Drawpile's free official community servers.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('24cc901e-5be4-49f1-a1da-9b6b8e0ccdd4', $q$Does Drawpile support animation?$q$, $q$Yes, Drawpile includes a timeline with onion-skinning for basic frame-by-frame animation.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('24cc901e-5be4-49f1-a1da-9b6b8e0ccdd4', $q$What happens if Drawpile crashes mid-session?$q$, $q$Drawpile can recover an interrupted session almost exactly where it left off, functioning as a replacement for traditional autosave.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('24cc901e-5be4-49f1-a1da-9b6b8e0ccdd4', $q$Real-time collaborative illustration$q$, $q$A group of artists works together on a single piece of art in real time, seeing each other's brushstrokes live.$q$, $q$Digital artists and art communities$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('24cc901e-5be4-49f1-a1da-9b6b8e0ccdd4', $q$Teaching digital painting$q$, $q$An instructor demonstrates brush techniques live while students draw alongside them in the same session.$q$, $q$Art educators and students$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('24cc901e-5be4-49f1-a1da-9b6b8e0ccdd4', $q$Livestreamed art sessions and battles$q$, $q$Streamers host live, multi-artist drawing sessions or friendly art battles that viewers can watch unfold in real time.$q$, $q$Content creators and hobbyist artists$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('24cc901e-5be4-49f1-a1da-9b6b8e0ccdd4', $q$Free (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full desktop and Android apps","Browser-based version","Access to free official community servers","Self-hosting option for private servers"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('24cc901e-5be4-49f1-a1da-9b6b8e0ccdd4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Drawpile is a free, open-source collaborative drawing and painting program that lets multiple users work on the same canvas simultaneously in real time.$q$, $q$The project, dating from 2014 under its current branding and rooted in earlier work by developer Calle Laakkonen, is legally organized under a German non-profit, Drawpile gemeinnützige UG, to keep the software permanently public and free.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('24cc901e-5be4-49f1-a1da-9b6b8e0ccdd4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$It includes over 200 built-in brushes, a custom brush editor, layers and blend modes, shape and selection tools, and support for OpenRaster and PSD file formats.$q$, $q$Animators get a timeline with onion-skinning, and every user benefits from a crash-recovery feature that restores a session almost exactly where it left off, plus a built-in timelapse recorder.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('24cc901e-5be4-49f1-a1da-9b6b8e0ccdd4', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Drawpile is entirely free under the GPLv3 license, with no subscription, paid tier, or company behind it.$q$, $q$Users can self-host a session server or connect to free official community servers, and password-protect sessions to keep them private.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('24cc901e-5be4-49f1-a1da-9b6b8e0ccdd4', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('24cc901e-5be4-49f1-a1da-9b6b8e0ccdd4', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('24cc901e-5be4-49f1-a1da-9b6b8e0ccdd4', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('24cc901e-5be4-49f1-a1da-9b6b8e0ccdd4', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('24cc901e-5be4-49f1-a1da-9b6b8e0ccdd4', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('24cc901e-5be4-49f1-a1da-9b6b8e0ccdd4', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$iPad-native, mobile-first EHR$q$, $q$Built from the outset for tablet use so clinicians can chart and review records at the point of care.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Integrated practice management$q$, $q$Appointment scheduling, calendar management, and staff workflows in the same system as clinical charting.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Revenue cycle management and billing$q$, $q$Automated claims submission and billing workflows, with more automation added at higher tiers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Patient portal$q$, $q$Lets patients book appointments, message their provider, and access records online.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Developer-friendly medical API$q$, $q$A documented API lets third-party developers and health-tech companies build integrations on top of DrChrono.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$E-prescribing and lab integrations$q$, $q$Supports electronic prescriptions and integration with lab services, with extended lab options available as an add-on.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Automated text, call, and fax reminders$q$, $q$Tiered monthly allotments of text messages, phone calls, and e-faxes to reduce patient no-shows and paperwork.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$AI clinical scribe (EverHealth Scribe)$q$, $q$AI-driven medical speech-to-text and automated clinical note generation, included in the Premium tier.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Strong mobile and tablet-first design heritage suited to point-of-care documentation$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$All-in-one suite covering EHR, billing, scheduling, and patient portal in a single system$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Developer-friendly API makes it popular with health-tech integrators and startups$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Now backed by EverCommerce's larger EverHealth group, adding financial stability and broader integrations$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Pricing is not published and requires a custom quote, making upfront cost comparison harder$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Costs can rise significantly at Growth and Premium tiers, reported up to 600-plus dollars per provider per month$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$AI scribe and advanced speech-to-text tools are only included by default at the top Premium tier$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Best suited to solo and small practices; larger health systems typically need more enterprise-focused platforms$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$How much does DrChrono cost?$q$, $q$DrChrono requires a custom quote, but third-party pricing trackers report costs roughly from 199 to 250 dollars per provider per month for the Foundation tier, rising to 300 to 600-plus dollars for Growth and Premium.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Who founded DrChrono and when?$q$, $q$DrChrono was founded in 2009 in California by Michael Nusimow and Daniel Kivatinos.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Is DrChrono still an independent company?$q$, $q$No. EverCommerce Inc. acquired DrChrono in November 2021 for a reported price around 180 million dollars, and it now operates under EverCommerce's EverHealth solutions group.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Does DrChrono have an API?$q$, $q$Yes, DrChrono offers a documented medical API that lets third-party developers build integrations with the platform.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$What pricing tiers does DrChrono offer?$q$, $q$DrChrono offers three tiers: Foundation, Growth, and Premium, each with increasing feature allotments for reminders, e-faxes, and automation.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$What are DrChrono's main competitors?$q$, $q$DrChrono competes with Kareo/Tebra, athenahealth, eClinicalWorks, and, for larger health systems, Epic.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Mobile charting for solo practitioners$q$, $q$A solo physician uses DrChrono on an iPad to chart patient visits and e-prescribe directly at the point of care.$q$, $q$Solo practitioners and small clinics$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$All-in-one billing and scheduling$q$, $q$A small practice consolidates scheduling, claims submission, and patient communication into one platform instead of separate tools.$q$, $q$Practice managers and billing staff$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Building health-tech integrations$q$, $q$A digital health startup uses DrChrono's medical API to connect its own application to practices' EHR data.$q$, $q$Health-tech developers and integrators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Foundation$q$, $q$~$199-$250/provider/month (third-party estimate)$q$, $q$Monthly, per provider$q$, NULL, $q$["Core EHR, practice management, and billing","250 text and 100 phone reminders/month","500 e-faxes/month","Unlimited email reminders and staff accounts"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Growth$q$, $q$Custom quote, higher than Foundation$q$, $q$Monthly, per provider$q$, NULL, $q$["Everything in Foundation","Advanced automated revenue cycle workflows","500 text and 250 phone reminders/month","1,000 e-faxes/month"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Premium$q$, $q$~$300-$600+/provider/month (third-party estimate)$q$, $q$Monthly, per provider$q$, NULL, $q$["Everything in Growth","AI-driven performance tools and EverHealth Scribe included","1,000 text and 750 phone reminders/month","2,000 e-faxes/month"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$DrChrono is a cloud-based EHR, practice management, and medical billing platform founded in 2009 by Michael Nusimow and Daniel Kivatinos as one of the first iPad-native electronic health record systems.$q$, $q$EverCommerce Inc. acquired DrChrono in November 2021 for a reported price around 180 million dollars, folding it into EverCommerce's EverHealth solutions group while keeping the DrChrono brand active.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform combines clinical charting, scheduling, revenue cycle management and medical billing, a patient portal, and e-prescribing into one suite, plus a developer-friendly medical API for third-party integrations.$q$, $q$Recent additions include AI-driven medical speech-to-text and the EverHealth Scribe AI clinical scribe tool, included by default in the top pricing tier.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$DrChrono sells three tiers — Foundation, Growth, and Premium — priced per provider per month, with exact figures available only via a custom quote.$q$, $q$Third-party pricing trackers report costs roughly from 199 to 250 dollars per provider per month at the Foundation level, rising to 300 to 600-plus dollars per provider per month for Growth and Premium plans with deeper billing automation and AI tools.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
